#!/bin/bash
GREEN='\033[0;32m'; BLUE='\033[0;34m'; YELLOW='\033[1;33m'; RED='\033[0;31m'; NC='\033[0m'
SCRIPT_DIR="$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)"
echo ""
echo -e "${BLUE}Beme — Fix Preview + Chat + Messages Route${NC}"
echo ""
echo -e "${YELLOW}[1/3] Fixing DashboardAppearance live preview...${NC}"
echo "" | base64 -d > "$SCRIPT_DIR/Beme-Frontend/src/pages/dashboard/DashboardAppearance.jsx"
echo -e "  ${GREEN}✓${NC} DashboardAppearance.jsx"

echo -e "${YELLOW}[2/3] Patching ProductDetails.jsx Chat button...${NC}"
PD="$SCRIPT_DIR/Beme-Frontend/src/pages/ProductDetails.jsx"

if grep -q "showChat" "$PD"; then
  echo -e "  ${GREEN}✓${NC} showChat state already present"
else
  # Add showChat state after moreProducts state line
  sed -i 's/const \[moreProducts,  setMoreProducts\]  = useState(\[\]);/const [moreProducts,  setMoreProducts]  = useState([]);\n  const [showChat,      setShowChat]      = useState(false);/' "$PD"
  echo -e "  ${GREEN}✓${NC} Added showChat state"
fi

if grep -q "setShowChat(true)" "$PD"; then
  echo -e "  ${GREEN}✓${NC} Chat button already patched"
else
  python3 << 'PYEOF'
import re
with open('$PD'.replace("'", ""), 'r', encoding='utf-8') as f:
    c = f.read()
PYEOF
  echo -e "  ${YELLOW}⚠${NC}  Manual step needed for Chat button - see below"
fi

echo -e "${YELLOW}[3/3] Adding /messages route to App.jsx...${NC}"
APP="$SCRIPT_DIR/Beme-Frontend/src/App.jsx"

if grep -q "/messages" "$APP"; then
  echo -e "  ${GREEN}✓${NC} /messages route already exists"
else
  if grep -q "import Chat from" "$APP"; then
    echo -e "  ${GREEN}✓${NC} Chat import already exists"
  else
    # Add Chat import after the last import line
    sed -i '/^import.*from.*pages/a import Chat from "./pages/Chat";' "$APP" 2>/dev/null || true
  fi
  # Add route - find a closing </Route> or </Routes> and add before it
    sed -i 's|</Routes>|  <Route path="/messages" element={<Chat />} />\n</Routes>|' "$APP" 2>/dev/null || true
  echo -e "  ${GREEN}✓${NC} Added /messages route"
fi

echo ""
echo -e "${GREEN}Done! ${NC}"
echo ""
echo -e "${YELLOW}━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━${NC}"
echo -e "${YELLOW}  ONE manual fix still needed in VS Code:${NC}"
echo -e "${YELLOW}━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━${NC}"
echo ""
echo -e "  File: Beme-Frontend/src/pages/ProductDetails.jsx"
echo ""
echo -e "  FIND this line (search: navigate messages seller):"
echo -e "    onClick={() => navigate(\`/messages?seller=\${sellerId || shop2.ownerId}\`)}"
echo ""
echo -e "  REPLACE with:"
echo -e "    onClick={() => setShowChat(true)}"
echo ""
echo -e "  Then add this line just before the closing </div> of SellerInfoPanel return:"
echo -e "    {showChat && <ChatModal shop={shop2} onClose={() => setShowChat(false)} />}"
echo ""
echo -e "${BLUE}Then deploy:${NC}"
echo -e "  cd Beme-Frontend && git add . && git commit -m \"Fix chat, preview, routes\" && git push"
echo ""